+            prop_assert_eq!(step, s);
+        } else {
+            prop_assert!(false, "Expected JumpTo variant");
+        }
+    }
+
+    #[test]
+    fn wait_condition_pane_id_none_for_default_constructors(
+        rule_id in "[a-z_]{3,15}",
